import React from "react";
import './project4.css'

function Project4() {
    return (
      <div id="project4-body" className="animate__animated animate__fadeInDown">
          <h4>Guesso</h4>
          <p id="project4-description">
            A full stack e-commerce clothing application. This project was developed as a group project, utilizing agile devlopment practices. Tech stack: REACT, HTML/CSS, Bootstrap, Node, Express, PostgreSQL, Render.
          </p>
          <div>
            <ul id="project4-links-ul">
                <li id="project4-link1"><a id="project1-link1" href="https://guessinggame1to100.netlify.app">View Site</a></li>
                <li id="project4-link2"><a id="project1-link2" href="https://github.com/ameyer12/guessing-game">GitHub</a></li>
            </ul>
          </div>
      </div>
    )
  }

export default Project4;
